async function checkRoute(path) {
  window.history.pushState({}, '', path);
  window.dispatchEvent(new PopStateEvent('popstate'));
  await new Promise(r => setTimeout(r, 200));
  const desktopNav = document.querySelector('.hidden.md\\:flex');
  const links = desktopNav ? desktopNav.querySelectorAll('a') : [];
  const active = [];
  links.forEach(a => { if (a.className.includes('text-[#D4AF37]') && a.className.includes('border-b-2')) active.push(a.textContent.trim()); });
  return { path, active };
}
// Check all routes sequentially
const results = [];
for (const p of ['/about', '/blog', '/contact', '/']) {
  results.push(await checkRoute(p));
}
results

